// /frontend/src/components/WeatherOverlay.jsx
import React, { useEffect, useMemo, useRef } from "react";

// --- Desktop MP4s ---
import fogday from "./overlays/desktop/fogday.mp4";
import fognight from "./overlays/desktop/fognight.mp4";
import pcday from "./overlays/desktop/pcday.mp4";
import pcnight from "./overlays/desktop/pcnight.mp4";
import clearday from "./overlays/desktop/clearday.mp4";
import clearnight from "./overlays/desktop/clearnight.mp4";
import cloudyday from "./overlays/desktop/cloudyday.mp4";
import cloudynight from "./overlays/desktop/cloudynight.mp4";
import rainday from "./overlays/desktop/rainday.mp4";
import rainnight from "./overlays/desktop/rainnight.mp4";
import thunderstormday from "./overlays/desktop/thunderstormday.mp4";
import thunderstormnight from "./overlays/desktop/thunderstormnight.mp4";
import snowday from "./overlays/desktop/snowday.mp4";
import snownight from "./overlays/desktop/snownight.mp4";

// --- Mobile MP4s ---
import fogdaymobile from "./overlays/mobile/fogdaymobile.mp4";
import fognightmobile from "./overlays/mobile/fognightmobile.mp4";
import pcdaymobile from "./overlays/mobile/pcdaymobile.mp4";
import pcnightmobile from "./overlays/mobile/pcnightmobile.mp4";
import cleardaymobile from "./overlays/mobile/cleardaymobile.mp4";
import clearnightmobile from "./overlays/mobile/clearnightmobile.mp4";
import cloudydaymobile from "./overlays/mobile/cloudydaymobile.mp4";
import cloudynightmobile from "./overlays/mobile/cloudynightmobile.mp4";
import raindaymobile from "./overlays/mobile/raindaymobile.mp4";
import rainnightmobile from "./overlays/mobile/rainnightmobile.mp4";
import thunderstormdaymobile from "./overlays/mobile/thunderstormdaymobile.mp4";
import thunderstormnightmobile from "./overlays/mobile/thunderstormnightmobile.mp4";
import snowdaymobile from "./overlays/mobile/snowdaymobile.mp4";
import snownightmobile from "./overlays/mobile/snownightmobile.mp4";

// Map for desktop videos
const OVERLAY_MAP_DESKTOP = {
  fogday,
  fognight,
  pcday,
  pcnight,
  clearday,
  clearnight,
  cloudyday,
  cloudynight,
  rainday,
  rainnight,
  thunderstormday,
  thunderstormnight,
  snowday,
  snownight,
};

// Map for mobile videos
const OVERLAY_MAP_MOBILE = {
  fogday: fogdaymobile,
  fognight: fognightmobile,
  pcday: pcdaymobile,
  pcnight: pcnightmobile,
  clearday: cleardaymobile,
  clearnight: clearnightmobile,
  cloudyday: cloudydaymobile,
  cloudynight: cloudynightmobile,
  rainday: raindaymobile,
  rainnight: rainnightmobile,
  thunderstormday: thunderstormdaymobile,
  thunderstormnight: thunderstormnightmobile,
  snowday: snowdaymobile,
  snownight: snownightmobile,
};

// Simple mobile check (coarse pointer or narrow viewport)
function isMobileLike() {
  if (typeof window === "undefined") return false;
  try {
    return (
      window.matchMedia?.("(pointer: coarse)")?.matches ||
      window.matchMedia?.("(max-width: 768px)")?.matches ||
      (navigator?.userAgent || "").toLowerCase().includes("mobi")
    );
  } catch {
    return false;
  }
}

// Map normalized condition + day/night -> key matching your file names
function pickKey(condition = "clear", isDay = true) {
  const c = (condition || "clear").toLowerCase();
  const dn = isDay ? "day" : "night";

  if (c.includes("thunder")) return `thunderstorm${dn}`;
  if (c.includes("heavy") && c.includes("rain")) return `rain${dn}`;
  if (c.includes("rain") || c.includes("drizzle")) return `rain${dn}`;
  if (c.includes("snow") || c.includes("sleet") || c.includes("hail")) return `snow${dn}`;
  if (c.includes("overcast")) return `cloudy${dn}`;
  if (c.includes("cloudy")) return `cloudy${dn}`;
  if (c.includes("partly") || c.includes("cloud")) return `pc${dn}`; // partly-cloudy
  if (c.includes("fog") || c.includes("mist") || c.includes("haze")) return `fog${dn}`;
  return `clear${dn}`;
}

export default function WeatherOverlay({
  condition = "clear", // one of: "clear" | "partly-cloudy" | "cloudy" | "rain" | "snow" | "fog" | "thunderstorm"
  isDay = true,
  className = "",
  opacity = 1,
}) {
  const mobile = isMobileLike();
  const key = pickKey(condition, isDay);

  const src = useMemo(() => {
    const map = mobile ? OVERLAY_MAP_MOBILE : OVERLAY_MAP_DESKTOP;
    return map[key] || (mobile ? OVERLAY_MAP_MOBILE.clearday : OVERLAY_MAP_DESKTOP.clearday);
  }, [key, mobile]);

  const vidRef = useRef(null);

  // Try autoplay safely on mount / swap
  useEffect(() => {
    const v = vidRef.current;
    if (!v) return;
    // Restart video when source changes
    v.pause();
    v.currentTime = 0;
    const play = v.play();
    if (play && typeof play.catch === "function") {
      play.catch(() => {
        // Some browsers require interaction; keep it muted and ready.
      });
    }
  }, [src]);

  // Respect prefers-reduced-motion by pausing video if user prefers less motion
  useEffect(() => {
    if (typeof window === "undefined" || !vidRef.current) return;
    const mq = window.matchMedia?.("(prefers-reduced-motion: reduce)");
    const onChange = () => {
      if (mq.matches) {
        vidRef.current.pause();
      } else {
        vidRef.current.play().catch(() => {});
      }
    };
    mq?.addEventListener?.("change", onChange);
    onChange();
    return () => mq?.removeEventListener?.("change", onChange);
  }, []);

  return (
    <div
      className={`absolute inset-0 z-0 pointer-events-none select-none ${className}`}
      style={{ opacity }}
      aria-hidden="true"
    >
      <video
        key={key}                 // force swap on condition changes
        ref={vidRef}
        src={src}
        autoPlay
        loop
        muted
        playsInline
        preload="auto"
        className="w-full h-full object-cover"
        disablePictureInPicture
      />
    </div>
  );
}
